// Parse the Shoutrrr generic webhook payload from Watchtower
const body = items[0].json.body || items[0].json;
const message = body.message || body.text || JSON.stringify(body);
const titleTag = body.title || 'unknown-host';

// Watchtower report format includes lines like:
// "Updating container /container_name abc123 -> def456"
// "Found new image for /container_name"
const lines = message.split('\n').filter(l => l.trim());

const updates = [];
for (const line of lines) {
  // Match "Updating /container_name" pattern
  const updateMatch = line.match(/(?:Updating|Updated)\s+(?:container\s+)?\/?([\w.-]+)/i);
  if (updateMatch) {
    updates.push({
      container: updateMatch[1],
      action: 'updated',
      host: titleTag,
      line: line.trim()
    });
    continue;
  }
  // Match "Found new image for /container_name" pattern  
  const foundMatch = line.match(/Found new (?:image|release) for \/?([\w.-]+)/i);
  if (foundMatch) {
    updates.push({
      container: foundMatch[1],
      action: 'available',
      host: titleTag,
      line: line.trim()
    });
  }
}

// If no individual containers parsed, treat as raw notification
if (updates.length === 0) {
  updates.push({
    container: 'unknown',
    action: 'notification',
    host: titleTag,
    line: message.substring(0, 500)
  });
}

return [{ json: { host: titleTag, updates, rawMessage: message } }];

const data = items[0].json;
const host = data.host;
const updates = data.updates;
const rawMessage = data.rawMessage;

// Homelab upgrade webhook (goes to #homelab-alerts channel)
const DISCORD_WEBHOOK = 'https://discord.com/api/webhooks/REDACTED/REDACTED';
const PUBLIC_HOOK_BASE = 'https://hooks.yourdomain.com/webhook';

// Build container status lines
const containerLines = updates.map(u => {
  if (u.action === 'updated') {
    return `✅ **${u.container}** — auto-updated`;
  } else if (u.action === 'available') {
    return `🔔 **${u.container}** — new image available`;
  } else {
    return `ℹ️ ${u.line}`;
  }
}).join('\n');

// Check if any container needs manual upgrade
const pendingUpgrades = updates.filter(u => u.action === 'available');
const hasManualActions = pendingUpgrades.length > 0;

// Build embed
const embed = {
  title: `🐳 Container Updates — ${host}`,
  color: hasManualActions ? 16750848 : 3066993,  // Orange if pending, Green if all auto
  description: containerLines,
  timestamp: new Date().toISOString(),
  footer: { text: 'Watchtower → n8n Upgrader' }
};

// Add upgrade action fields for each pending container
if (hasManualActions) {
  embed.fields = pendingUpgrades.map(u => ({
    name: `⚡ ${u.container}`,
    value: `[🚀 Upgrade Now](${PUBLIC_HOOK_BASE}/trigger-upgrade?container=${encodeURIComponent(u.container)}&host=${encodeURIComponent(host)}) ┃ [✖️ Ignore](${PUBLIC_HOOK_BASE}/ignore-upgrade?container=${encodeURIComponent(u.container)}&host=${encodeURIComponent(host)})`,
    inline: false
  }));
}

return [{ json: {
  webhookUrl: DISCORD_WEBHOOK + '?wait=true',
  payload: { embeds: [embed] },
  hasManualActions,
  pendingUpgrades,
  host
}}];

// Capture the Discord message ID from the ?wait=true response
const discordResponse = items[0].json;
const messageId = discordResponse.id;

// Now PATCH the original embed to inject the message ID into the upgrade links
// This is needed so the trigger-upgrade webhook knows which message to update
const prevData = $('Build Discord Embed').first().json;
const host = prevData.host;
const pendingUpgrades = prevData.pendingUpgrades || [];
const PUBLIC_HOOK_BASE = 'https://hooks.yourdomain.com/webhook';

if (pendingUpgrades.length > 0 && messageId) {
  // Rebuild fields with msgId now included
  const updatedFields = pendingUpgrades.map(u => ({
    name: `⚡ ${u.container}`,
    value: `[🚀 Upgrade Now](${PUBLIC_HOOK_BASE}/trigger-upgrade?container=${encodeURIComponent(u.container)}&host=${encodeURIComponent(host)}&msgId=${messageId}) ┃ [✖️ Ignore](${PUBLIC_HOOK_BASE}/ignore-upgrade?container=${encodeURIComponent(u.container)}&host=${encodeURIComponent(host)}&msgId=${messageId})`,
    inline: false
  }));

  // Build the patched embed
  const originalEmbed = prevData.payload.embeds[0];
  originalEmbed.fields = updatedFields;

  return [{ json: {
    messageId,
    patchUrl: prevData.webhookUrl.replace('?wait=true', '') + '/messages/' + messageId,
    patchPayload: { embeds: [originalEmbed] },
    needsPatch: true
  }}];
}

return [{ json: { messageId, needsPatch: false } }];

const query = items[0].json.query || $input.first().json.query || {};
const container = query.container || 'unknown';
const host = query.host || 'unknown';
const msgId = query.msgId || '';

// Map container names to stack names and paths
// This mapping defines which Semaphore template and extra vars to use
const STACK_MAP = {
  // automation-01 stacks
  'n8n': { stack: 'n8n', host: 'automation-01', path: '/opt/stacks/n8n' },
  'semaphore': { stack: 'semaphore', host: 'automation-01', path: '/opt/stacks/semaphore' },
  'forgejo': { stack: 'forgejo', host: 'automation-01', path: '/opt/stacks/forgejo' },
  'portainer': { stack: 'portainer', host: 'automation-01', path: '/opt/stacks/portainer' },
  'uptime-kuma': { stack: 'uptime-kuma', host: 'automation-01', path: '/opt/stacks/uptime-kuma' },
  'homepage': { stack: 'homepage', host: 'automation-01', path: '/opt/stacks/homepage' },
  'nginx-proxy-manager': { stack: 'nginx-proxy-manager', host: 'automation-01', path: '/opt/stacks/nginx-proxy-manager' },
  'netdata': { stack: 'netdata', host: 'automation-01', path: '/opt/stacks/netdata' },
  // docker-01 stacks
  'nextcloud-app': { stack: 'nextcloud', host: 'docker-01', path: '/opt/nextcloud-clean' },
  'nextcloud-redis': { stack: 'nextcloud', host: 'docker-01', path: '/opt/nextcloud-clean' },
  'nextcloud-db': { stack: 'nextcloud', host: 'docker-01', path: '/opt/nextcloud-clean' },
  'dozzle': { stack: 'dozzle', host: 'docker-01', path: '/opt/stacks/dozzle' },
  'cloudflared': { stack: 'cloudflared', host: 'docker-01', path: '/opt/stacks/cloudflared' },
  'portainer_agent': { stack: 'portainer-agent', host: 'docker-01', path: '/opt/stacks/portainer-agent' },
};

const mapping = STACK_MAP[container] || { stack: container, host: host, path: `/opt/stacks/${container}` };

return [{ json: {
  container,
  host,
  msgId,
  stackName: mapping.stack,
  targetHost: mapping.host,
  stackPath: mapping.path
}}];

// Extract the Semaphore task ID from the API response
const taskResponse = items[0].json;
const taskId = taskResponse.id;
const prevData = $('Resolve Stack Mapping').first().json;

return [{ json: {
  semaphoreTaskId: taskId,
  container: prevData.container,
  host: prevData.host,
  msgId: prevData.msgId,
  stackName: prevData.stackName,
  targetHost: prevData.targetHost,
  pollCount: 0
}}];

const taskStatus = items[0].json;
const prevData = $('Extract Semaphore Task ID').first().json;
const status = taskStatus.status;

// Semaphore statuses: 'waiting', 'running', 'success', 'error', 'stopped'
const isComplete = ['success', 'error', 'stopped'].includes(status);
const pollCount = (prevData.pollCount || 0) + 1;
const maxPolls = 40; // 40 * 15s = 10 min max wait

return [{ json: {
  ...prevData,
  status,
  isComplete: isComplete || pollCount >= maxPolls,
  isSuccess: status === 'success',
  pollCount
}}];

